import React, { FunctionComponent, useState } from "react";
import { ctx } from "../services/Context";
import {Button, H1, H2, Tab, Tabs} from "@blueprintjs/core";
import { observer } from "mobx-react";
import { Register } from "./Register";
import { Login } from "./Login";

export const Welcome: FunctionComponent<{ default_tab: string }> = props => {
  const [tab, setTab] = useState(props.default_tab);
  // const test: string = ctx.store.menu;
  return (
    <div className="body center">
      <div className="fx -w">
        <div className="curve-border">
            <H2>Heabank</H2>
            <p></p>
        </div>
        <div className="curve-border">
          <Tabs id="TabsExample" selectedTabId={tab}>
            <Tab
              id="lg"
              title="Login"
              onClickCapture={() => setTab("lg")}
              panel={<Login />}
              panelClassName="test-panel"
            />
            <Tab
              id="rg"
              title="Register"
              onClickCapture={() => setTab("rg")}
              panel={<Register />}
              panelClassName="ember-panel"
            />
            <Tabs.Expander />
          </Tabs>
        </div>
      </div>
    </div>
  );
};
